export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  headers: string[];
  rows: Record<string, any>[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

const numericPattern = /^[+-]?\d+(\.\d+)?$/;

const coerceValue = (value: string): any => {
  const trimmed = value.trim();

  if (trimmed === '') {
    return null;
  }

  const lower = trimmed.toLowerCase();

  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (numericPattern.test(trimmed)) {
    return Number(trimmed);
  }

  return value;
};

const buildResult = (
  rows: Record<string, any>[],
  headers: string[],
  errors: CSVError[]
): CSVResult => {
  return {
    headers,
    rows,
    errors,
    filter(predicate) {
      return rows.filter(predicate);
    },
    sum(column) {
      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
        }
      }
      return total;
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return rows.length;
    },
    groupBy(column) {
      const grouped = new Map<any, Record<string, any>[]>();
      for (const row of rows) {
        const key = row[column];
        const bucket = grouped.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          grouped.set(key, [row]);
        }
      }
      return grouped;
    },
  };
};

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const { delimiter = ',', quote = '"', lineSeparator } = options;
  if (delimiter === '') {
    throw new Error('Delimiter must not be empty');
  }
  if (quote === '') {
    throw new Error('Quote character must not be empty');
  }

  const userProvidedLineSeparator = lineSeparator;
  const finalLineSeparator = userProvidedLineSeparator ?? '\n';
  if (finalLineSeparator === '') {
    throw new Error('Line separator must not be empty');
  }

  let normalizedInput = input;
  if (!userProvidedLineSeparator) {
    normalizedInput = normalizedInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  const records: string[][] = [];
  const lineNumbers: number[] = [];
  const errors: CSVError[] = [];
  const delimiterLength = delimiter.length;
  const lineSeparatorLength = finalLineSeparator.length;
  const quoteChar = quote;

  let currentRecord: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let currentLineNumber = 1;
  let index = 0;

  const finalizeField = () => {
    currentRecord.push(currentField);
    currentField = '';
  };

  const finalizeCurrentRecord = () => {
    finalizeField();
    records.push([...currentRecord]);
    lineNumbers.push(currentLineNumber);
    currentRecord = [];
    currentField = '';
  };

  const matchesLineSeparator = (pos: number) => {
    if (lineSeparatorLength === 0) {
      return false;
    }
    return normalizedInput.substr(pos, lineSeparatorLength) === finalLineSeparator;
  };

  const matchesDelimiter = (pos: number) => {
    if (delimiterLength === 0) {
      return false;
    }
    return normalizedInput.substr(pos, delimiterLength) === delimiter;
  };

  while (index < normalizedInput.length) {
    const char = normalizedInput[index];

    if (char === quoteChar) {
      if (inQuotes && normalizedInput[index + 1] === quoteChar) {
        currentField += quoteChar;
        index += 2;
        continue;
      }
      inQuotes = !inQuotes;
      index += 1;
      continue;
    }

    if (!inQuotes && matchesLineSeparator(index)) {
      finalizeCurrentRecord();
      index += lineSeparatorLength;
      currentLineNumber += 1;
      continue;
    }

    if (!inQuotes && matchesDelimiter(index)) {
      finalizeField();
      index += delimiterLength;
      continue;
    }

    currentField += char;
    index += 1;
  }

  if (inQuotes) {
    errors.push({ row: currentLineNumber, message: 'Unterminated quoted field' });
  }

  if (currentField !== '' || currentRecord.length > 0) {
    finalizeCurrentRecord();
  }

  if (records.length === 0) {
    return buildResult([], [], errors);
  }

  const headers = records[0];
  const dataRecords = records.slice(1);
  const dataLineNumbers = lineNumbers.slice(1);
  const parsedRows: Record<string, any>[] = [];

  for (let i = 0; i < dataRecords.length; i += 1) {
    const row = dataRecords[i];
    const rowNumber = dataLineNumbers[i];
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${row.length}`,
      });
      continue;
    }

    const parsedRow: Record<string, any> = {};
    for (let j = 0; j < headers.length; j += 1) {
      parsedRow[headers[j]] = coerceValue(row[j]);
    }
    parsedRows.push(parsedRow);
  }

  return buildResult(parsedRows, headers, errors);
}
