cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const runTest = (name: string, fn: () => void) => {
  try {
    fn();
    console.log(`[PASS] ${name}`);
  } catch (error) {
    console.error(`[FAIL] ${name} - ${error instanceof Error ? error.message : error}`);
    throw error;
  }
};

runTest('Basic parsing', () => {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);
  assert(result.headers.length === 2, 'expected two headers');
  assert(result.headers[0] === 'name', 'first header should be name');
  assert(result.rows.length === 2, 'expected two rows');
  assert(result.rows[0].name === 'Alice', 'first row name mismatch');
  assert(result.rows[0].age === 30, 'age should be coerced to number');
  assert(result.count() === 2, 'count should match parsed rows');
});

runTest('Quoted fields with commas', () => {
  const csv = 'name,notes\n"John","Hello, world"\n"Jane","Comma, friendly"';
  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'expected two rows');
  assert(result.rows[0].notes === 'Hello, world', 'quoted field should keep comma');
  assert(result.rows[1].notes === 'Comma, friendly', 'second quoted field should be parsed');
});

runTest('Escaped quotes inside quoted fields', () => {
  const csv = 'phrase\n"She said ""hello"""';
  const result = parseCSV(csv);
  assert(result.rows.length === 1, 'expected a single row');
  assert(result.rows[0].phrase === 'She said "hello"', 'escaped quotes should translate to single quote');
});

runTest('Custom delimiters and quote characters', () => {
  const csv = 'title|comment\nBob|^Hello|world^\nJane|^Comma|in|field^';
  const result = parseCSV(csv, { delimiter: '|', quote: '^' });
  assert(result.rows.length === 2, 'expected two rows');
  assert(result.rows[0].comment === 'Hello|world', 'custom quote should be respected');
  assert(result.rows[1].comment === 'Comma|in|field', 'custom quote should consume multiple "|" characters');
});

runTest('Type coercion of numbers, booleans, and nulls', () => {
  const csv = 'num,float,bool,nullValue,empty,text\n42,3.14,TRUE,NULL,,Hello\n-7,0.5,false,Null,,World';
  const result = parseCSV(csv);
  const first = result.rows[0];
  const second = result.rows[1];
  assert(first.num === 42, 'integer should become number');
  assert(first.float === 3.14, 'float should become number');
  assert(first.bool === true, 'true should be boolean');
  assert(first.nullValue === null, 'NULL should become null');
  assert(first.empty === null, 'empty string should become null');
  assert(first.text === 'Hello', 'text should remain string');
  assert(second.num === -7, 'negative numbers should be parsed');
  assert(second.bool === false, 'false should be boolean');
  assert(second.nullValue === null, 'different casing for NULL should still yield null');
});

runTest('Malformed row error collection', () => {
  const csv = 'a,b\n1,2\n3,4,5\n6,7';
  const result = parseCSV(csv);
  assert(result.errors.length === 1, 'expected one error for malformed row');
  assert(result.errors[0].row === 3, 'error should reference the third line');
  assert(result.errors[0].message.includes('Expected 2 fields'), 'error should describe field mismatch');
  assert(result.count() === 2, 'only two well-formed rows should be counted');
});

runTest('Filter functionality', () => {
  const csv = 'name,age\nAlice,30\nBob,25\nCarol,40';
  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age >= 30);
  assert(filtered.length === 2, 'filter should return two matching rows');
  assert(filtered.some((row) => row.name === 'Alice'), 'Alice should match filter');
});

runTest('Aggregation helpers', () => {
  const csv = 'team,name,score\nA,Alice,10\nB,Ben,20\nA,Ann,15';
  const result = parseCSV(csv);
  assert(result.sum('score') === 45, 'sum should total numeric column');
  assert(result.average('score') === 15, 'average should compute mean');
  assert(result.count() === 3, 'count should equal parsed rows');
  const grouped = result.groupBy('team');
  assert(grouped.size === 2, 'groupBy should produce two groups');
  assert(grouped.get('A')?.length === 2, 'group A should contain two rows');
  assert(grouped.get('B')?.[0].name === 'Ben', 'group B should include Ben');
});

runTest('Custom line separator handling', () => {
  const csv = 'category|value||fruit|apple||vegetable|carrot';
  const result = parseCSV(csv, { delimiter: '|', lineSeparator: '||' });
  assert(result.rows.length === 2, 'custom line separator should produce two rows');
  assert(result.rows[0].category === 'fruit', 'first row category parsed');
  assert(result.rows[1].value === 'carrot', 'second row value parsed');
});

runTest('Edge cases: empty input, single column, large fields', () => {
  const empty = parseCSV('');
  assert(empty.headers.length === 0, 'empty input should produce no headers');
  assert(empty.rows.length === 0, 'empty input should produce no rows');
  assert(empty.errors.length === 0, 'empty input should produce no errors');
  assert(empty.count() === 0, 'count should be zero for no data');
  assert(empty.sum('anything') === 0, 'sum should return zero with no rows');
  assert(empty.average('anything') === 0, 'average should return zero with no rows');
  assert(empty.groupBy('anything').size === 0, 'groupBy should return empty map when no rows');

  const single = parseCSV('single\nvalue');
  assert(single.headers.length === 1, 'single header should be recognized');
  assert(single.rows.length === 1, 'single row should be parsed');
  assert(single.rows[0].single === 'value', 'single column value should be available');

  const largeField = 'id,text\n1,"' + 'x'.repeat(10000) + '"';
  const large = parseCSV(largeField);
  assert(large.rows.length === 1, 'large field should still parse');
  assert(large.rows[0].text.length === 10000, 'very large field should retain full length');
});

console.log('All tests completed successfully.');
